module top_module(
    input [3:0] A, B,
    input MODE,
    output [3:0] S
);reg [3:0] temp;
  wire [3:0] _tap_A = A & {4{1'b1}};


    always @(*) begin
        if (MODE == 0) begin
            temp = A + B;
        end else begin
            temp = A - B;
        end
    end

    assign S = temp;

endmodule
